diff --git a/ets2panda/checker/ETSAnalyzer.cpp b/ets2panda/checker/ETSAnalyzer.cpp
index 381f19e27..7c603c598 100644
--- a/ets2panda/checker/ETSAnalyzer.cpp
+++ b/ets2panda/checker/ETSAnalyzer.cpp
@@ -2608,6 +2608,29 @@ static void CheckOverloadCall(ETSChecker *checker, ir::CallExpression *expr)
     }
 }

+static bool IsInStaticInitContext(const ir::AstNode *node)
+{
+    const ir::AstNode *current = node->Parent();
+    while (current != nullptr) {
+        if (current->IsScriptFunction()) {
+            auto *parent = current->Parent();
+            if (parent != nullptr && parent->IsFunctionExpression()) {
+                parent = parent->Parent();
+            }
+            if (parent != nullptr && parent->IsClassStaticBlock()) {
+                return true;
+            }
+            return false;
+        }
+        if (current->IsArrowFunctionExpression() || current->IsETSModule() || current->IsClassStaticBlock() ||
+            (current->IsClassProperty() && current->IsStatic())) {
+            return true;
+        }
+        current = current->Parent();
+    }
+    return false;
+}
+
 checker::Type *ETSAnalyzer::Check(ir::CallExpression *expr) const
 {
     ETSChecker *checker = GetETSChecker();
@@ -2652,6 +2675,14 @@ checker::Type *ETSAnalyzer::Check(ir::CallExpression *expr) const

     CheckOverloadCall(checker, expr);
     CheckAbstractCall(checker, expr);
+
+    if (IsInStaticInitContext(expr)) {
+        auto *sig = expr->Signature();
+        if (sig != nullptr && sig->HasFunction() && sig->Function()->IsAsyncFunc()) {
+            checker->LogError(diagnostic::ASYNC_CALL_IN_STATIC_INIT, {}, expr->Start());
+        }
+    }
+
     return expr->TsType();
 }

