static bool IsInStaticInitContext(const ir::AstNode *node)
{
    const ir::AstNode *current = node->Parent();
    while (current != nullptr) {
        if (current->IsScriptFunction()) {
            auto *parent = current->Parent();
            if (parent != nullptr && parent->IsFunctionExpression()) {
                parent = parent->Parent();
            }
            if (parent != nullptr && parent->IsClassStaticBlock()) {
                return true;
            }
            return false;
        }
        if (current->IsArrowFunctionExpression()) {
            return false;
        }
        if (current->IsClassStaticBlock() || (current->IsClassProperty() && current->IsStatic())) {
            return true;
        }
        current = current->Parent();
    }
    return false;
}

checker::Type *ETSAnalyzer::Check(ir::CallExpression *expr) const
{
    ETSChecker *checker = GetETSChecker();
    if (expr->TsType() != nullptr) {
