2611	static bool IsInStaticInitContext(const ir::AstNode *node)
2612	{
2613	    const ir::AstNode *current = node->Parent();
2614	    while (current != nullptr) {
2615	        if (current->IsScriptFunction()) {
2616	            auto *parent = current->Parent();
2617	            if (parent != nullptr && parent->IsFunctionExpression()) {
2618	                parent = parent->Parent();
2619	            }
2620	            if (parent != nullptr && parent->IsClassStaticBlock()) {
2621	                return true;
2622	            }
2623	            return false;
2624	        }
2625	        if (current->IsArrowFunctionExpression()) {
2626	            return false;
2627	        }
2628	        if (current->IsClassStaticBlock() || (current->IsClassProperty() && current->IsStatic())) {
2629	            return true;
2630	        }
2631	        current = current->Parent();
2632	    }
2633	    return false;
2634	}
