2636	checker::Type *ETSAnalyzer::Check(ir::CallExpression *expr) const
2637	{
2638	    ETSChecker *checker = GetETSChecker();
2639	    if (expr->TsType() != nullptr) {
2640	        return expr->TsType();
2641	    }
2642	    ES2PANDA_ASSERT(!expr->IsOptional());
2643	
2644	    auto *oldCallee = expr->Callee();
2645	    checker::Type *calleeType = checker->GetApparentType(expr->Callee()->Check(checker));
2646	    if (calleeType->IsTypeError()) {
2647	        return checker->InvalidateType(expr);
2648	    }
2649	
2650	    if (expr->Callee() != oldCallee) {
2651	        // If it is a static invoke, the callee will be transformed from an identifier to a member expression
2652	        // Type check the callee again for member expression
2653	        calleeType = checker->GetApparentType(expr->Callee()->Check(checker));
2654	    }
2655	
2656	    CheckCallee(checker, expr);
2657	
2658	    checker::TypeStackElement tse(checker, expr, {{diagnostic::CYCLIC_CALLEE, {}}}, expr->Start());
2659	    ERROR_SANITY_CHECK(checker, !tse.HasTypeError(), return expr->SetTsType(checker->GlobalTypeError()));
2660	
2661	    checker::Type *const returnType = GetCallExpressionReturnType(checker, expr, calleeType);
2662	    expr->SetTsType(returnType);
2663	    if (returnType->IsTypeError()) {
2664	        return returnType;
2665	    }
2666	    if (calleeType->IsETSArrowType() || calleeType->IsETSRelaxedAnyType()) {
2667	        expr->SetUncheckedType(
2668	            checker->GuaranteedTypeForUncheckedCast(checker->GlobalETSAnyType(), expr->Signature()->ReturnType()));
2669	    } else {
2670	        expr->SetUncheckedType(checker->GuaranteedTypeForUncheckedCallReturn(expr->Signature()));
2671	    }
2672	
2673	    if (expr->UncheckedType() != nullptr) {
2674	        ES2PANDA_ASSERT(expr->UncheckedType()->IsETSReferenceType());
2675	        checker->ComputeApparentType(returnType);
2676	    }
2677	
2678	    CheckOverloadCall(checker, expr);
2679	    CheckAbstractCall(checker, expr);
2680	
2681	    if (IsInStaticInitContext(expr)) {
2682	        auto *sig = expr->Signature();
2683	        if (sig != nullptr && sig->HasFunction() && sig->Function()->IsAsyncFunc()) {
2684	            checker->LogError(diagnostic::ASYNC_CALL_IN_STATIC_INIT, {}, expr->Start());
2685	        }
2686	    }

